class Solution {
public:
    long long countGoodIntegers(int n, int k) {
        long long res = 0;
        vector<int> cnt(10, 0);
        cnt[0] = 1; // to avoid leading zeros
        for (int i = 0; i < n; ++i) {
            vector<int> nxt(cnt.size(), 0);
            for (int j = 0; j < 10; ++j) {
                for (int d = 0; d < 10; ++d) {
                    int num = (j * 10 + d) % k;
                    nxt[num] += cnt[j];
                }
            }
            cnt = nxt;
        }
        return cnt[0];
    }
};
efficiency: HIGH
time complexity: O(N*K*10)
space complexity: O(K)
energy implications: LOW
explanation: Utilizes dynamic programming to track counts of numbers modulo k, efficiently computing the count of good integers by iterating through digits and updating counts accordingly. 
